jQuery(function($){"use strict";$(".wpmake-advance-user-avatar-enhanced-select").select2();var $notice=$("#wpmake-aua-review-notice");if($notice.length){function sendDismiss(type,cb){$.post(wpmake_aua_admin_params.ajax_url,{action:"wpmake_advance_user_avatar_upload_dismiss_notice",security:wpmake_aua_admin_params.notice_nonce,dismissed:true,type:type},function(){if(typeof cb==="function")cb();})}$notice.find(".notice-link-visit").on("click",function(){sendDismiss("rated");$notice.slideUp();});$notice.find(".notice-later").on("click",function(e){e.preventDefault();sendDismiss("later");$notice.slideUp();});$notice.find(".notice-dismiss-permanently").on("click",function(e){e.preventDefault();sendDismiss("rated");$notice.slideUp();})}});
